from flask import Flask, request, send_from_directory, jsonify
import os
import shutil

app = Flask(__name__)

# Sample in-memory storage (replace with a real database or file system)
root_dir = '/tmp/files'

@app.route('/list', methods=['GET'])
def list_dir():
    path = request.args.get('path')
    if not path:
        return jsonify({'error': 'Path is required'})
    norm_path = os.path.normpath(os.path.join(root_dir, path))
    try:
        files = os.listdir(norm_path)
        files.sort()
        return jsonify({'files': files})
    except FileNotFoundError:
        return jsonify({'error': 'Directory not found'})

@app.route('/download', methods=['GET'])
def download_file():
    path = request.args.get('path')
    if not path:
        return jsonify({'error': 'Path is required'})
    norm_path = os.path.normpath(os.path.join(root_dir, path))
    try:
        filename = os.path.basename(norm_path)
        return send_from_directory(os.path.dirname(norm_path), filename, as_attachment=True)
    except FileNotFoundError:
        return jsonify({'error': 'File not found'})

@app.route('/info', methods=['GET'])
def get_file_info():
    path = request.args.get('path')
    if not path:
        return jsonify({'error': 'Path is required'})
    norm_path = os.path.normpath(os.path.join(root_dir, path))
    try:
        stats = os.stat(norm_path)
        return jsonify({
            'size': stats.st_size,
            'modified': stats.st_mtime,
            'accessed': stats.st_atime
        })
    except FileNotFoundError:
        return jsonify({'error': 'File not found'})

if __name__ == '__main__':
    app.run(debug=True)